import { useEffect } from "react";
import { get, set } from "idb-keyval";

interface UseRestoreFromIndexedDBOptions {
  key: string;
  setValue: (value: string) => void;
  dependencies?: any[];
  onLoad?: (value: string) => void;
}

export function useRestorePrompt({
  key,
  setValue,
  dependencies = [],
  onLoad,
}: UseRestoreFromIndexedDBOptions) {
  useEffect(() => {
    const loadStoredValue = async () => {
      try {
        const storedValue = await get(key);
        if (storedValue && typeof storedValue === "string") {
          setValue(storedValue);
          if (onLoad) {
            onLoad(storedValue);
          }
        }
      } catch (error) {
        console.error(`Failed to load value from IndexedDB for key "${key}":`, error);
      }
    };

    loadStoredValue();
  }, [key, setValue, onLoad, ...dependencies]);
}

/**
 * Utility function to save a value to IndexedDB
 * @param key - The IndexedDB key to save the value to
 * @param value - The value to save
 */
export async function saveToIndexedDB(key: string, value: string): Promise<void> {
  try {
    await set(key, value);
  } catch (error) {
    console.error(`Failed to save value to IndexedDB for key "${key}":`, error);
    throw error;
  }
}

